<?php
declare(strict_types=1);
require_once __DIR__.'/../includes/ecosystem.php';$wallet=beyond_app_bootstrap('DailyBreath');$pdo=beyond_db();$userId=(int)$_SESSION['user_id'];
$slug=preg_replace('/[^a-z0-9-]/','',strtolower((string)($_GET['course']??$_POST['course']??'')));$s=$pdo->prepare('SELECT * FROM academy_courses WHERE slug=? AND is_published=1');$s->execute([$slug]);$course=$s->fetch(PDO::FETCH_ASSOC);if(!$course){http_response_code(404);exit('Module not found.');}$s=$pdo->prepare('SELECT * FROM academy_lessons WHERE course_id=? AND is_published=1 ORDER BY lesson_number');$s->execute([$course['id']]);$lessons=$s->fetchAll(PDO::FETCH_ASSOC);
$passedCount=0;$q=$pdo->prepare('SELECT COUNT(DISTINCT lesson_id) FROM academy_quiz_attempts WHERE user_id=? AND passed=1 AND lesson_id IN(SELECT id FROM academy_lessons WHERE course_id=?)');$q->execute([$userId,$course['id']]);$passedCount=(int)$q->fetchColumn();if($passedCount<count($lessons)){header('Location: course.php?course='.rawurlencode($slug).'&lesson=1&locked=1');exit;}
$quiz=[];foreach($lessons as $i=>$lesson){$wrong=[];foreach($lessons as $candidate)if($candidate['id']!==$lesson['id'])$wrong[]=$candidate['title'];$options=array_slice($wrong,$i,3);while(count($options)<3)$options[]=$wrong[count($options)]??'None of these';$slot=$i%4;array_splice($options,$slot,0,[$lesson['title']]);$quiz[]=['Which topic belongs to Lesson '.($i+1).'?',$options,$slot];}
$message='';$score=null;$passed=false;$reward=null;if($_SERVER['REQUEST_METHOD']==='POST'){if(!verify_csrf_token($_POST['csrf']??null))$message='Your session expired.';else{$score=0;$answers=[];foreach($quiz as $i=>$question){$answer=(int)($_POST['q'][$i]??-1);$answers[$i]=$answer;if($answer===$question[2])$score++;}$passed=$score>=8;$pdo->prepare('INSERT INTO academy_module_exam_attempts(user_id,course_id,score,question_count,passed,answers_json) VALUES(?,?,?,?,?,?)')->execute([$userId,$course['id'],$score,count($quiz),$passed?1:0,json_encode($answers)]);if($passed)$reward=beyond_award_reward($userId,'dailybreath','module',(string)$course['id'],50,'Bible Academy module completed — '.$course['title']);$message=$passed?'Module exam passed. Your achievement is saved.'.(!empty($reward['awarded'])?' +50 bit$ earned.':''):'Score '.$score.'/'.count($quiz).'. Review the lessons and retry; 80% is required.';}}
?><!doctype html><html><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Module Exam | Bible Academy</title><style>body{margin:0;color:#eef5ed;font-family:Inter,system-ui;background:#062416}.shell{max-width:820px;margin:auto;padding:45px 20px 80px}.card{padding:clamp(22px,5vw,42px);border:1px solid #ffffff33;border-radius:26px;background:#0c3928}.question{padding:20px 0;border-bottom:1px solid #ffffff24}.option{display:block;margin:8px 0;padding:11px;border-radius:11px;background:#ffffff0c}.btn{display:inline-flex;margin-top:20px;padding:13px 18px;border:0;border-radius:12px;color:#173f2c;background:#f0cf7e;text-decoration:none;font-weight:900}.notice{padding:14px;border-radius:13px;color:#173f2c;background:#f0cf7e}a{color:#f0cf7e}</style></head><body><main class="shell"><a href="academy.php">← Bible Academy</a><section class="card"><p>MODULE EXAM</p><h1><?=e($course['title'])?></h1><p>Answer all <?=count($quiz)?> questions. Score 80% or higher to complete this module.</p><?php if($message):?><div class="notice"><?=e($message)?></div><?php endif;?><?php if($passed):?><a class="btn" href="academy.php">Return to Academy →</a><?php else:?><form method="post"><input type="hidden" name="csrf" value="<?=e(csrf_token())?>"><input type="hidden" name="course" value="<?=e($slug)?>"><?php foreach($quiz as $i=>$question):?><fieldset class="question"><h3><?=($i+1)?>. <?=e($question[0])?></h3><?php foreach($question[1] as $j=>$option):?><label class="option"><input type="radio" name="q[<?=$i?>]" value="<?=$j?>" required> <?=e($option)?></label><?php endforeach;?></fieldset><?php endforeach;?><button class="btn">Submit module exam</button></form><?php endif;?></section></main><script src="/assets/js/visitor-analytics.js" defer></script></body></html>
